fun techQuestionsExpert3(): List<Question> = listOf(
    Question(categoryId = 7, questionText = "Was besagt das FLP-Unmoeglichkeitstheorem (Fischer, Lynch, Paterson 1985)?", answerA = "Ein verteiltes System kann keine Byzantine-Fehler tolerieren", answerB = "In einem asynchronen verteilten System ist Konsens mit auch nur einem fehlerhaften Prozess nicht loesbar", answerC = "Konsens ist nur moeglich wenn alle Nachrichten in geordneter Reihenfolge eintreffen", answerD = "Ein verteiltes System kann hoechstens n/2 Ausfaelle tolerieren", correctAnswer = 1, explanation = "FLP beweist: Im vollstaendig asynchronen Modell kann kein deterministischer Algorithmus Konsens garantieren wenn auch nur ein Prozess crashen kann. Die Praxis loest dies durch Timeouts und verlaesst damit das rein asynchrone Modell.", difficulty = 4, funFact = "Dieses Theorem erklaert warum alle praxistauglichen Konsens-Protokolle wie Paxos oder Raft Timeouts verwenden muessen."),
    Question(categoryId = 7, questionText = "Wie funktioniert ein Lamport-Timestamp und welche Eigenschaft garantiert er?", answerA = "Lamport-Timestamps sind physikalische Uhrzeiten die per NTP synchronisiert werden", answerB = "Ein logischer Zaehler der bei jedem Senden erhoehen und beim Empfangen auf max(lokal, empfangen)+1 gesetzt wird um happened-before Ordnung einzuhalten", answerC = "Ein kryptografisches Token das die Reihenfolge von Transaktionen beweist", answerD = "Ein Vektoruhren-Spezialfall fuer Zwei-Knoten-Systeme", correctAnswer = 1, explanation = "Lamport-Timestamps garantieren: Wenn Ereignis A vor B stattfand (A happened-before B), dann ist timestamp(A) < timestamp(B). Die Umkehrung gilt nicht - gleiche Timestamps beweisen keine kausale Ordnung.", difficulty = 4, funFact = "Leslie Lamport veroeffentlichte diese Idee 1978 im Paper Time, Clocks, and the Ordering of Events - eines der meistzitierten Informatik-Paper ueberhaupt."),
    Question(categoryId = 7, questionText = "Was leisten Vektoruhren (Vector Clocks) gegenueber Lamport-Timestamps?", answerA = "Vektoruhren sind schneller zu berechnen als Lamport-Timestamps", answerB = "Vektoruhren erkennen echte Kausalitaet: zwei Ereignisse koennen als konkurrent (weder happened-before noch after) identifiziert werden", answerC = "Vektoruhren erfordern weniger Speicher als Lamport-Timestamps", answerD = "Vektoruhren funktionieren ohne Nachrichtenuebergabe zwischen Prozessen", correctAnswer = 1, explanation = "Mit Vektoruhren gilt: A happened-before B genau dann wenn VC(A)[i] <= VC(B)[i] fuer alle i. Ist weder A <= B noch B <= A sind beide kausal unabhaengig (konkurrent). Lamport-Timestamps koennen Nebenlaeufer nicht von geordneten Ereignissen unterscheiden.", difficulty = 4, funFact = "Amazon Dynamo nutzt Vektoruhren um Schreibkonflikte zu erkennen. Wenn zwei Writes konkurrent sind muss der Client den Konflikt selbst aufloesen."),
    Question(categoryId = 7, questionText = "Was versteht man unter Byzantine Fault Tolerance (BFT) und wie viele fehlerhafte Knoten kann ein BFT-System tolerieren?", answerA = "BFT toleriert Netzwerkpartitionen und benoetigt mindestens n/2+1 Knoten", answerB = "BFT toleriert willkuerlich boeswilliges Verhalten und benoetigt mindestens 3f+1 Gesamtknoten um f Byzantine-Knoten zu tolerieren", answerC = "BFT ist nur in synchronen Systemen anwendbar und erfordert digitale Signaturen", answerD = "BFT toleriert Crash-Ausfaelle und benoetigt mindestens 2f+1 Knoten", correctAnswer = 1, explanation = "Im Byzantine Generals Problem braucht ein System mit n Knoten mindestens 3f+1 Knoten um f Byzantine-Knoten zu tolerieren. Das PBFT-Protokoll von Castro und Liskov war der erste praktische BFT-Algorithmus.", difficulty = 4, funFact = "Blockchain-Systeme wie Tendermint implementieren BFT fuer Konsens. Bitcoin nutzt stattdessen Proof-of-Work als Sybil-Resistenz."),
    Question(categoryId = 7, questionText = "Was ist das CAP-Theorem und welche zwei Eigenschaften kann ein System bei Netzwerkpartition gleichzeitig garantieren?", answerA = "Bei Netzwerkpartition muss zwischen Konsistenz und Partition-Toleranz gewaehlt werden - Verfuegbarkeit ist immer garantierbar", answerB = "Bei Netzwerkpartition muss ein System zwischen Konsistenz (C) und Verfuegbarkeit (A) waehlen da Partition-Toleranz (P) in verteilten Systemen unvermeidlich ist", answerC = "CAP besagt dass alle drei Eigenschaften gleichzeitig erreichbar sind bei ausreichender Replikation", answerD = "Das CAP-Theorem gilt nur fuer Datenbanksysteme nicht fuer allgemeine verteilte Systeme", correctAnswer = 1, explanation = "Da Netzwerkpartitionen unvermeidlich sind muss ein System zwischen CP (Konsistenz priorisiert) und AP (Verfuegbarkeit priorisiert) waehlen. HBase ist CP, Cassandra ist AP.", difficulty = 4, funFact = "Eric Brewer stellte das CAP-Theorem 2000 als Vermutung vor, Gilbert und Lynch bewiesen es 2002 formal. PACELC ist eine Erweiterung die auch Latenz einbezieht."),
    Question(categoryId = 7, questionText = "Wie funktioniert die Leader-Wahl im Raft-Konsens-Protokoll?", answerA = "Alle Knoten waehlen gleichzeitig durch Broadcast und der Knoten mit dem hoechsten Wert gewinnt", answerB = "Ein Kandidat erhoeht seinen Term, sendet RequestVote an alle Knoten und wird Leader wenn er eine Mehrheit der Stimmen erhaelt bevor sein Timeout ablaeuft", answerC = "Raft waehlt den Leader deterministisch nach Prozess-ID aufsteigend", answerD = "Der erste gestartete Knoten wird automatisch Leader und bleibt es bis er crasht", correctAnswer = 1, explanation = "Follower starten nach randomisiertem Election-Timeout als Kandidaten, erhoehen den Term und sammeln Stimmen. Der Kandidat mit Quorum wird Leader und sendet Heartbeats. Randomisierung verhindert Split-Vote-Situationen.", difficulty = 4, funFact = "Raft wurde 2013 als verstaendlichere Alternative zu Paxos entworfen. Das Paper heisst bewusst In Search of an Understandable Consensus Algorithm."),
    Question(categoryId = 7, questionText = "Was ist MVCC (Multi-Version Concurrency Control) und wie vermeidet es Read-Write-Konflikte?", answerA = "MVCC ist ein Locking-Protokoll das optimistisches Locking implementiert", answerB = "MVCC sperrt Zeilen fuer Leseoperationen und erhoeht dadurch die Datenkonsistenz", answerC = "MVCC komprimiert Datenbankseiten automatisch wenn mehrere Versionen akkumulieren", answerD = "MVCC speichert mehrere Versionen jeder Zeile sodass Leser alte Snapshots sehen ohne Schreiber zu blockieren und umgekehrt", correctAnswer = 3, explanation = "Jede Transaktion erhaelt einen Snapshot-Zeitstempel und sieht den Datenbankzustand zu ihrem Start. Schreiber erzeugen neue Versionen. Alte Versionen werden durch Vacuum oder GC bereinigt.", difficulty = 4, funFact = "PostgreSQL implementiert MVCC nativ - jede Zeile hat xmin/xmax-Felder fuer Sichtbarkeit. InnoDB nutzt einen separaten Undo-Log fuer alte Versionen."),
    Question(categoryId = 7, questionText = "Was ist Write-Ahead Logging (WAL) und welche zwei Datenbankgarantien liefert es?", answerA = "WAL schreibt Daten zuerst in den Cache und dann verzoegert auf Disk fuer bessere Performance", answerB = "WAL schreibt Aenderungen zuerst in ein sequentielles Log bevor Datenpages aktualisiert werden und garantiert Atomaritaet und Durability auch bei Crashes", answerC = "WAL ist ein Replikations-Protokoll das Slave-Datenbanken synchron haelt", answerD = "WAL verhindert Dirty Reads durch eine separate Sperrtabelle", correctAnswer = 1, explanation = "WAL garantiert Atomaritaet (bei Crash wird das Log bei Neustart angewendet oder rueckgaengig gemacht) und Durability (committed Transaktionen ueberleben Crashes weil der Log-Eintrag vor dem Commit fsync wird).", difficulty = 4, funFact = "PostgreSQL WAL ermoeglicht auch Point-in-Time Recovery und Streaming Replication. Major-Versions-Upgrades erfordern pg_upgrade weil das WAL-Format stabil gehalten wird."),
    Question(categoryId = 7, questionText = "Wie funktioniert B-Tree-Node-Splitting beim Einfuegen und was passiert wenn die Wurzel voll ist?", answerA = "B-Tree-Knoten koennen unbegrenzt wachsen ohne gesplittet zu werden", answerB = "Beim Split werden beide Haelften in neue Blaetter umgewandelt ohne den Elternknoten zu aendern", answerC = "Ein voller Knoten wird in zwei Haelften geteilt, der mittlere Schluessel in den Elternknoten hochgezogen - ist die Wurzel voll entsteht eine neue Wurzel und der Baum waechst in der Hoehe", answerD = "Der volle Knoten wird geloescht und neu aufgebaut dann wird der neue Schluessel eingefuegt", correctAnswer = 2, explanation = "Beim B-Tree-Split wird der Median zum Elternknoten hochgezogen. Ist der Elternknoten auch voll propagiert der Split aufwaerts. Eine volle Wurzel erzeugt eine neue Wurzel - so waechst der Baum nach oben.", difficulty = 4, funFact = "InnoDB verwendet einen B+-Tree wo alle Daten in Blaettern liegen. NTFS und ext4 nutzen B-Trees fuer Verzeichnisse."),
    Question(categoryId = 7, questionText = "Was ist ein Log-Structured Merge-Tree (LSM-Tree) und fuer welche Workloads ist er optimiert?", answerA = "LSM-Trees sind fuer Lesezugriffe optimiert durch Bloom-Filter in jedem Level", answerB = "Ein LSM-Tree ist ein balancierter Binaerbaum der Logs komprimiert", answerC = "LSM-Trees sind eine Variante von B-Trees mit zusaetzlichem Caching", answerD = "LSM-Trees schreiben Aenderungen sequentiell in einen In-Memory-Buffer (MemTable) und immutable Disk-Schichten (SSTables) und sind fuer schreibintensive Workloads optimiert", correctAnswer = 3, explanation = "LSM-Trees wandeln zufaellige Schreibzugriffe in sequentielle Disk-Writes um. MemTable-Overflow wird als immutable SSTable geflusht. Background-Compaction merged Schichten. Bloom-Filter reduzieren unnoetige Disk-Reads.", difficulty = 4, funFact = "RocksDB, LevelDB, Apache Cassandra und HBase verwenden LSM-Trees. Google BigTable (2006) machte LSM-Trees popular."),
    Question(categoryId = 7, questionText = "Was ist Hindley-Milner-Typinferenz und welche Klasse von Programmen kann sie typisieren?", answerA = "Ein Typsystem das nur einfache Typen wie Integer und Boolean inferiert", answerB = "Ein Algorithmus (Algorithm W) der fuer den Lambda-Kalkuel mit Let-Polymorphismus den allgemeinsten Typ ohne explizite Annotationen inferiert", answerC = "Ein Laufzeit-Typsystem das Typen zur Ausfuehrungszeit prueft", answerD = "Ein Typsystem das nur ohne Generics funktioniert", correctAnswer = 1, explanation = "HM-Typinferenz inferiert vollstaendig den Typ jedes Ausdrucks im typisierten Lambda-Kalkuel mit Let-Polymorphismus durch Unifikation. Die Komplexitaet ist im Normalfall fast linear.", difficulty = 4, funFact = "Haskell und ML basieren auf HM. OCaml nutzt es direkt. Rust und Scala haben Erweiterungen die ueber reines HM hinausgehen."),
    Question(categoryId = 7, questionText = "Was ist der IPC-Overhead-Nachteil eines Mikrokernel-Betriebssystems gegenueber einem monolithischen Kernel?", answerA = "Monolithische Kernel sind unsicherer weil alle Module als separate Prozesse laufen", answerB = "Mikrokernel benoetigen mehr RAM weil alle Dienste redundant ausgefuehrt werden", answerC = "Im Microkernel werden Treiber und Services als Userspace-Prozesse ausgefuehrt was jeden Systemaufruf durch teures Context-Switching und IPC verlangsamt", answerD = "Mikrokernel haben keinen messbaren Performance-Nachteil gegenueber monolithischen Kerneln", correctAnswer = 2, explanation = "Im Microkernel laufen Dateisystem, Treiber und Netzwerkstack als Userspace-Prozesse. Jeder Systemaufruf erfordert mindestens zwei Kontextwechsel und IPC-Botschaften. Modernes IPC kann den Overhead auf ca. 10% reduzieren.", difficulty = 4, funFact = "macOS und iOS nutzen den Mach-Mikrokernel als Basis kombiniert mit BSD-Schichten im Kernelspace (hybride Architektur). seL4 ist der erste formal verifizierte Betriebssystemkern."),
    Question(categoryId = 7, questionText = "Was ist ein TLB-Shootdown und wann wird er ausgefuehrt?", answerA = "Ein TLB-Shootdown tritt auf wenn der CPU-Cache durch einen DMA-Transfer korrupt wird", answerB = "Wenn ein Prozess eine Seite freigibt oder Page-Tabellen aendert muessen alle CPUs ihre TLB-Eintraege fuer diese Adresse per Inter-Processor-Interrupt (IPI) invalidieren", answerC = "Ein TLB-Shootdown ist das Leeren des gesamten TLB beim Context-Switch zwischen Prozessen", answerD = "TLB-Shootdowns werden durch den Memory-Controller ausgeloest wenn Seiten zwischen NUMA-Nodes verschoben werden", correctAnswer = 1, explanation = "TLBs cachen virtuelle-zu-physische Adressuebersetzungen. Wenn ein Mapping ungueltig wird muss der Kernel per IPI alle anderen CPUs zwingen den TLB-Eintrag zu loeschen. Dies ist teuer bei vielen Cores.", difficulty = 4, funFact = "TLB-Shootdowns sind ein bekannter Skalierungsengpass in Linux bei vielen Threads die Speicher teilen. Der Kernel batcht Shootdowns wenn moeglich."),
    Question(categoryId = 7, questionText = "Was beschreibt Page-Table-Walking in modernen x86-64 CPUs und wie viele Speicherzugriffe benoetigt es?", answerA = "Das Durchsuchen des Seitentausches nach ausgelagerten Pages - benoetigt 1 Speicherzugriff", answerB = "Das Hardware-gesteuerte Traversieren der 4-stufigen Seitentabelle bei TLB-Miss benoetigt 4 Speicherzugriffe (PML4 -> PDPT -> PD -> PT)", answerC = "Das Software-gesteuerte Laden von Seitentabellen durch den OS-Kernel - benoetigt 2 Speicherzugriffe", answerD = "Die Berechnung der physischen Adresse direkt aus der virtuellen Adresse ohne Speicherzugriff", correctAnswer = 1, explanation = "Bei einem TLB-Miss traversiert die MMU-Hardware autonom die 4-Level-Seitentabelle. CR3 zeigt auf PML4, jeder 9-Bit-Indexanteil der virtuellen Adresse selektiert einen Eintrag - insgesamt 4 Speicherzugriffe.", difficulty = 4, funFact = "Intel Ice Lake fuehrte 5-Level-Paging (PML5) mit 5 Speicherzugriffen ein. Spectre-Variant-4 betrifft speziell spekulative Ausfuehrung waehrend Page-Table-Walks."),
    Question(categoryId = 7, questionText = "Was ist Memory-Mapped I/O (MMIO) und wie unterscheidet es sich von Port-Mapped I/O (PMIO) auf x86?", answerA = "MMIO ist langsamer als PMIO wegen virtueller Adressumsetzung", answerB = "MMIO und PMIO sind auf modernen CPUs identisch implementiert", answerC = "MMIO nutzt spezielle IN/OUT-Instruktionen, PMIO nutzt normale Load/Store-Instruktionen", answerD = "MMIO mappt Hardware-Register in den normalen Adressraum sodass Load/Store-Instruktionen Geraete steuern, PMIO nutzt separate IN/OUT-Instruktionen und einen eigenen 64KB-Adressraum", correctAnswer = 3, explanation = "x86 hat historisch beide Modi: PMIO mit IN/OUT-Instruktionen (PCI Legacy), MMIO mappt Geraete-Register in den physischen Adressraum (non-cached). Moderne PCIe-Geraete nutzen ausschliesslich MMIO.", difficulty = 4, funFact = "ARM, RISC-V und die meisten modernen ISAs verwenden nur MMIO und kennen keinen separaten I/O-Adressraum. x86 haelt PMIO nur noch aus Legacy-Gruenden aufrecht."),
    Question(categoryId = 7, questionText = "Wie funktioniert der Mark-and-Sweep-Garbage-Collection-Algorithmus und was ist sein Hauptproblem?", answerA = "Mark-and-Sweep kopiert lebende Objekte in einen neuen Bereich - Hauptproblem ist hoher Speicherverbrauch", answerB = "Mark-and-Sweep markiert alle erreichbaren Objekte vom Root-Set ausgehend und gibt alle nicht-markierten frei - Hauptproblem ist Heap-Fragmentierung", answerC = "Mark-and-Sweep zaehlt Referenzen und gibt Objekte mit Zaehler 0 frei - Hauptproblem sind Zyklen", answerD = "Mark-and-Sweep teilt den Heap in zwei Haelften und ist speicherineffizient", correctAnswer = 1, explanation = "Mark-Phase traversiert das Objektgraph vom Root-Set und markiert alle erreichbaren Objekte. Sweep-Phase durchsucht den gesamten Heap und gibt nicht-markierte frei. Resultat: fragmentierter Heap da tote Objekte zwischen lebenden lagen.", difficulty = 4, funFact = "John McCarthy erfand Mark-and-Sweep 1960 fuer LISP. Modernes GC wie JVM G1 und ZGC kombiniert es mit Kompaktierung und Generational-Ansaetzen."),
    Question(categoryId = 7, questionText = "Was ist der Tri-Color-Marking-Algorithmus und wozu dient er in concurrent GCs?", answerA = "Ein Algorithmus der den Heap in drei physische Bereiche aufteilt fuer bessere Cache-Nutzung", answerB = "Ein inkrementeller Marking-Algorithmus der Objekte als weiss (unbesucht), grau (Kinder unbesucht) oder schwarz (vollstaendig verarbeitet) faerbt um GC nebenlaeufig zur Applikation zu betreiben", answerC = "Ein Farbcodierungs-Schema fuer Typen in der Hindley-Milner-Typinferenz", answerD = "Ein Algorithmus zur Erkennung von Referenzzyklen in reference-counting GCs", correctAnswer = 1, explanation = "Tri-Color-Invariante: Kein schwarzes Objekt zeigt direkt auf ein weisses Objekt. Write-Barriers sichern die Invariante wenn der Mutator Zeiger waehrend des GC veraendert. Dies erlaubt concurrent GC.", difficulty = 4, funFact = "ZGC und Shenandoah in der JVM implementieren concurrent Mark-Compact basierend auf Tri-Color-Marking und erreichen sub-Millisekunden GC-Pausen."),
    Question(categoryId = 7, questionText = "Was ist Generational Garbage Collection und welche Hypothese liegt ihr zugrunde?", answerA = "Generational GC verwaltet verschiedene Objektgroessen in separaten Heap-Bereichen", answerB = "GC wird in regelmaessigen Zeitintervallen ausgefuehrt um Pausen gleichmaessig zu verteilen", answerC = "Generational GC kompiliert Klassen in native Generationen unterschiedlicher Optimierungsstufen", answerD = "Basierend auf der Generational Hypothesis (die meisten Objekte sterben jung) teilt Generational GC den Heap in junge und alte Generationen und sammelt junge Generationen haeufiger", correctAnswer = 3, explanation = "Die empirisch belegte Generational Hypothesis: 80-90% aller Objekte sterben kurz nach ihrer Erzeugung. Minor GC sammelt den Young-Heap haeufig mit geringer Pause. Langlebige Objekte werden in den Old-Heap befoerdert.", difficulty = 4, funFact = "HotSpot JVM nutzt drei Generationen: Eden, Survivor 0/1 und Old. G1GC und ZGC haben die klassischen Generationsgrenzen teilweise aufgeweicht nutzen aber weiterhin Generational-Ansaetze."),
    Question(categoryId = 7, questionText = "Was ist das Dining-Philosophers-Problem und welcher Mechanismus loest es ohne Deadlock?", answerA = "Das Problem beschreibt Race-Conditions beim Lesen gemeinsamer Variablen geloest durch Mutex-Locks", answerB = "Fuenf Philosophen teilen Gabeln und Deadlock entsteht wenn alle gleichzeitig die linke Gabel nehmen. Loesung: Resource-Hierarchy (Ressourcen immer in Reihenfolge anfordern) oder Arbitrator-Pattern", answerC = "Das Problem wird durch Semaphoren mit Counter=5 geloest die alle Gabeln atomar reservieren", answerD = "Das Dining-Philosophers-Problem ist nur theoretisch und hat keine praktische Relevanz", correctAnswer = 1, explanation = "Deadlock entsteht durch zyklische Wartebedingung: alle halten linke Gabel und warten auf rechte. Resource-Hierarchy: Philosophen nehmen immer zuerst die Gabel mit der niedrigeren Nummer. Alternativ erlaubt ein Arbitrator nur 4 Philosophen gleichzeitig.", difficulty = 4, funFact = "Dijkstra formulierte das Problem 1965 als Pruefungsfrage. Es demonstriert die vier Coffman-Bedingungen: mutual exclusion, hold-and-wait, no preemption, circular wait."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen optimistischem und pessimistischem Locking in Datenbanken?", answerA = "Pessimistisches Locking ist schneller bei geringer Konfliktrate, optimistisches bei hoher", answerB = "Pessimistisches Locking sperrt Zeilen vor dem Lesen (SELECT FOR UPDATE). Optimistisches Locking liest ohne Sperre und prueft bei COMMIT ob sich die Version geaendert hat", answerC = "Optimistisches Locking verwendet Exklusiv-Locks, pessimistisches Shared-Locks", answerD = "Pessimistisches Locking erfordert explizite BEGIN TRANSACTION Anweisungen, optimistisches nicht", correctAnswer = 1, explanation = "Bei niedrigem Konflikt ist optimistisches Locking effizienter. Bei hohem Konflikt verursacht es viele abgebrochene Transaktionen. Pessimistisches Locking blockiert Concurrency verhindert aber Konflikte von vornherein.", difficulty = 4, funFact = "JPA/Hibernate implementiert optimistisches Locking mit @Version-Annotation. DynamoDB nutzt konditionelle Writes als optimistisches Locking ohne explizite Transaktion."),
    Question(categoryId = 7, questionText = "Was ist Consistent Hashing und welches Problem loest es in verteilten Cache-Systemen?", answerA = "Consistent Hashing vermeidet Kollisionen durch doppelte Hashing-Stufen", answerB = "Consistent Hashing ist ein kryptografisches Hash-Verfahren fuer sichere Schluesselverteilung", answerC = "Consistent Hashing bildet Knoten und Schluessel auf einem Ring ab sodass beim Hinzufuegen oder Entfernen eines Knotens nur O(K/N) Schluessel neu verteilt werden statt O(K)", answerD = "Consistent Hashing garantiert dass alle Schluessel gleichmaessig auf alle Knoten verteilt werden", correctAnswer = 2, explanation = "Bei einfachem Modulo-Hashing muss bei n+1 Knoten fast der gesamte Cache neu verteilt werden. Consistent Hashing platziert Knoten auf einem Ring. Beim Wegfall eines Knotens uebernimmt nur sein Nachfolger dessen Schluessel.", difficulty = 4, funFact = "Amazon Dynamo, Apache Cassandra und Memcached nutzen Consistent Hashing. Virtuelle Knoten (VNodes) verbessern die Gleichverteilung."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen Linearizability und Sequential Consistency als Konsistenzmodelle?", answerA = "Beide Modelle sind identisch - nur der Name unterscheidet sich je nach Literatur", answerB = "Linearizability erfordert dass jede Operation instantan an einem realen Zeitpunkt wirksam wird. Sequential Consistency erlaubt globale Ordnung ohne Echtzeit-Constraint", answerC = "Sequential Consistency ist staerker als Linearizability weil es mehr Garantien bietet", answerD = "Linearizability ist nur in Single-Core-Systemen erreichbar, Sequential Consistency in Multi-Core", correctAnswer = 1, explanation = "Linearizability ist staerker: jede Operation erscheint atomar an einem Linearization Point zwischen Aufruf und Rueckkehr. Sequential Consistency erlaubt beliebige globale Ordnungen solange jeder Thread seine Programmreihenfolge sieht.", difficulty = 4, funFact = "Google Spanner bietet externe Konsistenz (staerker als Linearizability) durch True Time API mit GPS-Uhren und Atomuhren in jedem Datacenter."),
    Question(categoryId = 7, questionText = "Wie funktioniert Basic Paxos und welche Phasen hat es?", answerA = "Paxos hat drei Phasen: Prepare, Accept und Learn - ein Proposer sendet Prepare mit Ballot-Nummer, sammelt Promises und sendet Accept mit dem Wert des hoechsten Promised-Ballots", answerB = "Paxos hat zwei Phasen: Leader-Wahl und Value-Broadcast ohne Quorum-Anforderung", answerC = "Paxos verwendet nur eine Phase und benoetigt Einstimmigkeit aller Knoten", answerD = "Basic Paxos hat vier Phasen: Discover, Propose, Vote und Commit wie in zwei-Phasen-Commit", correctAnswer = 0, explanation = "Phase 1 (Prepare/Promise): Proposer sendet Prepare(n) an Mehrheit, Acceptors versprechen keine kleineren Ballots. Phase 2 (Accept/Accepted): Proposer sendet Accept(n, v) mit dem Wert des hoechsten Promises. Bei Quorum ist Konsens erreicht.", difficulty = 4, funFact = "Leslie Lamport veroeffentlichte Paxos 1989 aber es wurde zuerst abgelehnt als zu ungewoehnlich. Es gilt als das fundamentale Konsens-Protokoll auf dem Raft und Multi-Paxos basieren."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen Two-Phase Commit (2PC) und Three-Phase Commit (3PC)?", answerA = "3PC ist identisch mit 2PC aber mit einem zusaetzlichen Logging-Schritt", answerB = "2PC kann bei Coordinator-Crash zu unendlichem Blockieren fuehren. 3PC fuegt eine Pre-Commit-Phase ein um dies bei synchronen Netzwerken zu vermeiden", answerC = "3PC unterstuetzt mehr Teilnehmer als 2PC und skaliert besser", answerD = "2PC und 3PC sind aequivalent in ihrer Fehlertoleranz bei Netzwerkpartitionen", correctAnswer = 1, explanation = "In 2PC koennen Participants nach PREPARE und vor dem Coordinator-Ergebnis blockiert bleiben. 3PC fuegt PRE-COMMIT ein damit Participants die Entscheidung rekonstruieren koennen.", difficulty = 4, funFact = "Trotz theoretischer Vorteile wird 3PC kaum eingesetzt weil auch 3PC bei Netzwerkpartitionen scheitert. Moderne Systeme nutzen Saga-Pattern oder Spanner-Transaktionen."),
    Question(categoryId = 7, questionText = "Was ist Structural Subtyping (Duck Typing) vs Nominal Subtyping und welche Sprachen verwenden welches System?", answerA = "Duck Typing ist identisch mit dynamischer Typisierung und hat mit Subtyping nichts zu tun", answerB = "Structural Subtyping ist nur in funktionalen Sprachen moeglich, Nominal Subtyping in OOP-Sprachen", answerC = "Structural Subtyping prueft Namen der Typen (class A extends B), Nominal prueft die Struktur", answerD = "Nominal Subtyping (Java, C#) erfordert explizite Subtyp-Deklaration. Structural Subtyping (Go, TypeScript) genuegt es wenn ein Typ alle geforderten Methoden hat ohne explizite Deklaration", correctAnswer = 3, explanation = "In Go implementiert ein Typ ein Interface implizit wenn er alle Methoden hat - kein implements-Keyword noetig. TypeScript ist strukturell. Java erfordert explizites implements.", difficulty = 4, funFact = "Haskell-Typklassen sind weder nominal noch strukturell - sie sind ad-hoc Polymorphismus. Rust Traits sind nominal fuer Typen aber die Implementierung erfolgt extern vom Typ."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen Eager Evaluation und Lazy Evaluation in der Programmiersprachen-Semantik?", answerA = "Eager Evaluation ist langsamer aber speichereffizienter als Lazy Evaluation", answerB = "Eager Evaluation wertet Ausdruecke sofort aus. Lazy Evaluation (call-by-need) wertet erst aus wenn der Wert benoetigt wird und cached das Ergebnis als Thunk", answerC = "Lazy Evaluation ist identisch mit call-by-name und evaluiert Ausdruecke mehrfach", answerD = "Eager Evaluation ist das Standardmodell in Haskell, Lazy in Kotlin und Java", correctAnswer = 1, explanation = "Call-by-value (Eager): Argument vor Funktionsaufruf ausgewertet. Call-by-need (Lazy): Erster Zugriff wertet aus und cached das Ergebnis. Haskell ist call-by-need und ermoeglicht damit unendliche Listen.", difficulty = 4, funFact = "Haskells Lazy Evaluation ermoeglicht take 10 [1..] fuer die ersten 10 natuerlichen Zahlen. Der Preis sind schwer vorhersagbare Space Leaks durch aufgebaute Thunk-Ketten."),
    Question(categoryId = 7, questionText = "Was ist Continuation-Passing Style (CPS) und welche Compileroptimierung macht er moeglich?", answerA = "CPS ist ein Speicherallokationsschema das Stack-Frames durch Heap-Objekte ersetzt", answerB = "CPS ist eine Technik zur statischen Analyse von Kontrollfluss ohne Transformation", answerC = "CPS ist eine Methode zur Parallelisierung von Funktionsaufrufen durch explizite Thread-Kontinuationen", answerD = "CPS ist eine Transformation bei der jede Funktion eine explizite Continuation-Funktion als Parameter erhaelt statt normal zurueckzukehren, was Tail-Call-Elimination aller Aufrufe ermoeglicht", correctAnswer = 3, explanation = "In CPS gibt eine Funktion ihr Ergebnis an die Continuation k weiter. Da jeder Aufruf damit ein Tail-Call ist kann er als Jump optimiert werden. Scheme-Compiler und GHC nutzen CPS als intermediaere Darstellung.", difficulty = 4, funFact = "Async/Await in Kotlin, C# und Python sind im Wesentlichen CPS-transformierter Code. CPS-Transformation ist aequivalent zur SSA-Form die LLVM fuer Optimierungen nutzt."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen Monoid, Funktor und Monad in der funktionalen Programmierung?", answerA = "Monad ist eine Erweiterung von Funktor mit map, Funktor eine Erweiterung von Monoid mit append", answerB = "Monoid: Menge mit assoziativem Operator und neutralem Element. Funktor: Typkonstruktor mit fmap. Monad: Funktor mit bind (>>=) und return fuer Verkettung mit Kontext-Management", answerC = "Alle drei sind identische Konzepte mit unterschiedlichen Namen je nach Sprache", answerD = "Monad ist ein Design-Pattern, Funktor und Monoid sind mathematische Strukturen ohne Praxisrelevanz", correctAnswer = 1, explanation = "Monoid: (a <> b) <> c = a <> (b <> c) und mempty <> a = a. Funktor: fmap (f . g) = fmap f . fmap g. Monad: m >>= return = m. Jede Monad ist ein Funktor.", difficulty = 4, funFact = "Philip Wadler popularisierte Monaden fuer Programmierung 1992. Die Aussage A monad is just a monoid in the category of endofunctors ist korrekt aber fuer Einfuehrungszwecke wenig hilfreich."),
    Question(categoryId = 7, questionText = "Was ist Software-Transaktionsspeicher (STM) und wie unterscheidet er sich von Mutex-basiertem Locking?", answerA = "STM erfordert Hardware-Unterstuetzung (TSX) und laeuft nicht auf Standard-CPUs", answerB = "STM und Mutex sind identisch - STM ist nur ein modernerer Name fuer dasselbe Konzept", answerC = "STM erlaubt deklarative Komposition von Transaktionen ohne manuelle Lock-Reihenfolge und vermeidet Deadlocks durch Retry-Semantik ist aber bei hohem Konflikt langsamer", answerD = "STM ist immer langsamer als Mutex-Locking weil es Transaktionslogs fuehren muss", correctAnswer = 2, explanation = "STM (Haskell STM, Clojure Refs) fuehrt alle Variablenzugriffe in einem Transaktionslog. Bei Commit wird auf Konflikte geprueft - falls ja wird die Transaktion automatisch wiederholt. Kein explizites Locking, keine Deadlocks.", difficulty = 4, funFact = "Haskell STM ist durch das Typsystem gesichert: IO-Aktionen sind in STM-Transaktionen verboten. Dies verhindert Bugs wo nicht-idempotente Aktionen bei Retry mehrfach ausgefuehrt werden."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen Row-Level Locking und Table-Level Locking bezueglich Deadlock-Risiko?", answerA = "Table-Level Locking hat hoehere Deadlock-Wahrscheinlichkeit als Row-Level Locking", answerB = "Row-Level Locking erlaubt hoehere Concurrency erhoehe aber das Deadlock-Risiko da Transaktionen mehrere Zeilen in unterschiedlicher Reihenfolge sperren koennen", answerC = "Beides ist identisch in modernen Datenbanken durch automatische Lock-Eskalation", answerD = "Deadlocks sind bei Row-Level Locking unmoeglich weil jede Zeile eine eigene Sperrtabelle hat", correctAnswer = 1, explanation = "Mit Row-Level Locks kann Transaktion A Zeile 1 sperren und auf Zeile 2 warten waehrend Transaktion B Zeile 2 haelt und auf Zeile 1 wartet - klassischer Deadlock. Datenbanken erkennen Deadlocks durch Wait-for-Graphs.", difficulty = 4, funFact = "InnoDB implementiert Row-Level Locks durch Gap-Locks und Next-Key-Locks um Phantom-Reads zu verhindern. PostgreSQL nutzt den Lock-Manager fuer Table-Locks."),
    Question(categoryId = 7, questionText = "Was ist Speculative Execution in modernen CPUs und welche Sicherheitsluecke hat sie verursacht?", answerA = "Spekulative Ausfuehrung ist eine Debugtechnik um Code vor seiner eigentlichen Ausfuehrung zu testen", answerB = "CPUs fuehren Instruktionen hinter Branches spekulativ aus. Spectre nutzt dies: spekulativ ausgefuehrter Code aendert den Cache-Zustand und verraet Geheimnisse via Timing-Seitenkanal", answerC = "Speculative Execution betrifft nur SIMD-Einheiten und ist durch SSE-Flags deaktivierbar", answerD = "Spekulative Ausfuehrung erhoehte den Strombedarf und verursachte thermische Probleme", correctAnswer = 1, explanation = "Ohne spekulative Ausfuehrung muesste die CPU bei jedem Branch warten. Prozessoren sagen Branches vorher und fuehren spekulativ aus. Spectre v1: spekulativer Code laedt geheime Daten in den Cache, ein Timing-Angriff liest den Cache-Zustand aus.", difficulty = 4, funFact = "Retpoline von Google verhindert spekulatives Springen auf Indirect Branches. Der Performance-Einbruch war je nach Workload 5-30% und betraf fast alle CPUs der letzten 20 Jahre."),
    Question(categoryId = 7, questionText = "Was ist das NUMA (Non-Uniform Memory Access) Problem und wie beeinflusst es Mehrkern-Performance?", answerA = "NUMA ist ein veraltetes Problem das durch DDR5 vollstaendig geloest wurde", answerB = "NUMA betrifft nur GPU-Speicher und ist fuer CPU-Programmierung irrelevant", answerC = "In NUMA-Systemen haben CPUs schnelleren Zugriff auf ihren lokalen Speicher als auf den Speicher anderer NUMA-Knoten - Remote-Zugriffe haben 2-4x hoehere Latenz", answerD = "NUMA beschreibt unterschiedliche Cache-Groessen der CPU-Kerne die zu inkonsistentem Verhalten fuehren", correctAnswer = 2, explanation = "In Multi-Socket-Servern hat jeder CPU-Socket seinen eigenen Speichercontroller. Greift CPU 0 auf Speicher von CPU 1 zu muss die Anfrage ueber QPI/UPI (AMD: Infinity Fabric) gehen.", difficulty = 4, funFact = "AMD EPYC CPUs haben extreme NUMA-Topologie: 8 CCDs mit eigenen L3-Caches. Das BIOS-Setting NPS (NUMA per Socket) ist konfigurierbar."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen einer Semaphore und einem Mutex?", answerA = "Mutex und Semaphore sind identisch - nur der Initialwert unterscheidet sich", answerB = "Ein Mutex ist ein binaerer Lock der nur vom erwerbenden Thread freigegeben werden darf (Ownership-Semantik). Eine Semaphore ist ein Zaehler ohne Ownership der von verschiedenen Threads signalisiert werden kann", answerC = "Semaphoren koennen nur in Userspace verwendet werden, Mutex ist ein Kernel-Primitiv", answerD = "Ein Mutex erlaubt mehrere gleichzeitige Zugriffe, eine Semaphore nur einen", correctAnswer = 1, explanation = "Mutex: Thread A acquires, nur Thread A kann release aufrufen. Semaphore(n): n Threads gleichzeitig. wait() dekrementiert, signal() inkrementiert. Ein binaerer Semaphore erlaubt im Gegensatz zum Mutex release() von einem anderen Thread.", difficulty = 4, funFact = "Edsger Dijkstra erfand Semaphoren 1965. P() und V() kommen aus dem Niederlaendischen: passeren und vrijgeven. POSIX-Semaphore koennen auch prozessuebergreifend genutzt werden."),
    Question(categoryId = 7, questionText = "Was ist ein Bloom Filter und welche Art von falschem Ergebnis kann er produzieren?", answerA = "Ein Bloom Filter kann False Negatives produzieren - er sagt ein Element ist nicht enthalten obwohl es enthalten ist", answerB = "Ein Bloom Filter ist eine probabilistische Datenstruktur die False Positives produzieren kann aber niemals False Negatives", answerC = "Bloom Filter produzieren keinerlei falsche Ergebnisse bei korrekter Dimensionierung", answerD = "Bloom Filter koennen sowohl False Positives als auch False Negatives produzieren je nach Hash-Funktion", correctAnswer = 1, explanation = "Alle k Bits gesetzt bedeutet moeglicherweise enthalten (koennte false positive sein durch andere Elemente). Mindestens ein Bit nicht gesetzt bedeutet definitiv nicht enthalten. False Negatives sind unmoeglich da einmal gesetzte Bits nie geloescht werden.", difficulty = 4, funFact = "RocksDB und Cassandra nutzen Bloom Filter pro SSTable um unnoetige Disk-Reads zu vermeiden. Chromium nutzt einen Bloom Filter fuer Safe-Browsing-Lookups."),
    Question(categoryId = 7, questionText = "Was ist der Dijkstra-Algorithmus und welche Zeitkomplexitaet hat er mit einem Fibonacci-Heap?", answerA = "Dijkstra hat mit einem Fibonacci-Heap O(V log V + E) und findet kuerzeste Pfade auch in Graphen mit negativen Kanten", answerB = "Dijkstra findet kuerzeste Pfade in Graphen mit nicht-negativen Kanten und erreicht mit Fibonacci-Heap O(V log V + E) durch amortisiert O(1) decrease-key Operationen", answerC = "Dijkstra hat immer O(V^2) Zeitkomplexitaet unabhaengig von der Prioritaetswarteschlangen-Implementierung", answerD = "Dijkstra funktioniert mit Fibonacci-Heap nur bei dichten Graphen mit E = O(V^2)", correctAnswer = 1, explanation = "Mit Binary Heap: O((V+E) log V). Mit Fibonacci-Heap: O(V log V + E) da decrease-key amortisiert O(1). Dijkstra funktioniert NICHT bei negativen Kantengewichten - dafuer dient Bellman-Ford O(VE).", difficulty = 4, funFact = "Dijkstra entwickelte den Algorithmus 1956 in etwa 20 Minuten ohne Stift und Papier nur im Kopf. Er ist einer der meistimplementierten Algorithmen der Welt."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen einem Interpreter und einem JIT-Compiler?", answerA = "JIT-Compiler uebersetzen den Quellcode einmalig vor der Ausfuehrung, Interpreter zur Laufzeit", answerB = "Ein Interpreter fuehrt Bytecode Schritt fuer Schritt aus. Ein JIT-Compiler erkennt haeufig ausgefuehrten Code (Hot Paths) zur Laufzeit und kompiliert ihn in nativen Maschinencode fuer deutlich hoehere Geschwindigkeit", answerC = "JIT-Compiler sind immer langsamer als AOT-Compiler weil sie Kompilierzeit zur Laufzeit haben", answerD = "Interpreter koennen keine Typinformationen nutzen, JIT-Compiler sind typsicher", correctAnswer = 1, explanation = "JVM HotSpot: Bytecode wird interpretiert, ein Profiler zaehlt Invocations. Nach einem Schwellenwert kompiliert der JIT in nativen x86-Code. Tier-Compilation: C1 (schnell) und C2 (aggressiv optimierend mit Profil-Daten).", difficulty = 4, funFact = "V8 nutzt Sparkplug (Baseline-JIT), Maglev (Mid-Tier-JIT) und TurboFan (Optimierender JIT). LuaJIT gilt als einer der schnellsten JITs ueberhaupt."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen einem Software-Interrupt und einem Hardware-Interrupt?", answerA = "Software-Interrupts sind langsamer als Hardware-Interrupts weil sie durch den OS-Kernel geroutet werden", answerB = "Hardware-Interrupts werden durch externe Geraete asynchron ausgeloest. Software-Interrupts (Traps/Syscalls) werden durch spezielle CPU-Instruktionen (SYSCALL) synchron vom laufenden Programm ausgeloest", answerC = "Software-Interrupts umgehen den Interrupt-Controller und sind immer priorisiert", answerD = "Hardware-Interrupts koennen nicht maskiert werden, Software-Interrupts schon", correctAnswer = 1, explanation = "Hardware-IRQs: PIC/APIC signalisiert CPU asynchron (Timer, NIC RX). Software-Interrupt: SYSCALL (64-bit) oder Exception (Page Fault, Division by Zero). Alle nutzen die IDT (Interrupt Descriptor Table).", difficulty = 4, funFact = "x86-64 nutzt SYSCALL/SYSRET statt INT 0x80 weil es keinen Privilege-Level-Check der IDT durchfuehrt und damit ca. 10x schneller ist."),
    Question(categoryId = 7, questionText = "Was ist Copy-on-Write (CoW) und wie nutzt der Linux-Kernel es nach fork()?", answerA = "CoW erstellt beim fork() sofort vollstaendige Kopien aller Speicherseiten fuer den Child-Prozess", answerB = "Nach fork() teilen Parent und Child alle Speicherseiten als read-only. Erst bei einem Schreibzugriff wird die betreffende Seite fuer den schreibenden Prozess kopiert", answerC = "CoW ist eine Optimierung fuer Dateioperationen und hat nichts mit fork() zu tun", answerD = "CoW erfordert spezielle Hardware-Unterstuetzung durch CoW-faehige RAM-Controller", correctAnswer = 1, explanation = "Linux fork() ist O(1) dank CoW: Nur Seitentabellen werden kopiert, alle Pages auf read-only gesetzt. Beim ersten Write-Zugriff triggert die MMU einen Page-Fault. Der Kernel alloziert eine neue Page, kopiert den Inhalt und setzt sie als writable.", difficulty = 4, funFact = "Auch Btrfs und ZFS nutzen CoW: Schreiboperationen erzeugen neue Bloecke statt vorhandene zu ueberschreiben. Dies ermoeglicht atomare Snapshots und einfaches Rollback."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen Kernel Threads und User Threads (Green Threads)?", answerA = "Kernel Threads sind immer schneller als User Threads weil sie direkt auf Hardware zugreifen", answerB = "Kernel Threads werden vom OS-Scheduler verwaltet und koennen auf mehrere CPUs verteilt werden. User Threads laufen in der Laufzeitbibliothek normalerweise auf einem Kernel Thread ohne echtes Parallelismus", answerC = "Green Threads sind veraltet und werden in modernen Sprachen nicht mehr eingesetzt", answerD = "Kernel Threads benoetigen keine Context-Switches, User Threads schon", correctAnswer = 1, explanation = "M:N-Threading (Go Goroutines): Viele User-Thread-aehnliche Konstrukte werden auf N Kernel-Threads gemappt. Go GOMAXPROCS steuert die Anzahl der OS-Threads. Goroutinen koennen echt parallel laufen und sind preemtiv seit Go 1.14.", difficulty = 4, funFact = "Java Virtual Threads (JDK 21, Project Loom) bringen Green Threads zu Java: Millionen von Virtual Threads werden auf einen Thread-Pool von Platform-Threads gemappt."),
    Question(categoryId = 7, questionText = "Was ist Lock-Free Programming und wie unterscheidet es sich von Wait-Free?", answerA = "Lock-Free und Wait-Free sind Synonyme fuer non-blocking Algorithmen", answerB = "Lock-Free garantiert systemweiten Fortschritt: mindestens ein Thread macht immer Fortschritt, andere koennen verhungern. Wait-Free garantiert individuellen Fortschritt: JEDER Thread schliesst in begrenzter Schrittzahl ab", answerC = "Lock-Free verwendet Mutexe ohne Deadlock-Risiko, Wait-Free verwendet keine Synchronisation", answerD = "Wait-Free ist schwaecher als Lock-Free weil es keine Fortschrittsgarantien bietet", correctAnswer = 1, explanation = "Lock-Free: CAS-Loops koennen einzelne Threads verhungern lassen wenn immer andere gewinnen. Wait-Free: jede Operation schliesst in endlicher Schrittzahl ab. java.util.concurrent.AtomicInteger ist lock-free.", difficulty = 4, funFact = "Maurice Herlihy bewies 1991: Read-Write-Register haben Consensus-Zahl 1, CAS hat Consensus-Zahl unendlich - deshalb ist x86-CAS so fundamental fuer Lock-Free-Algorithmen."),
    Question(categoryId = 7, questionText = "Was ist das ABA-Problem in lock-freien Algorithmen und wie wird es geloest?", answerA = "Das ABA-Problem tritt auf wenn ein Wert von A nach B und zurueck nach A geaendert wird, ein CAS-Vorgang es faelschlicherweise als unveraendert betrachtet und damit eine inkonsistente Aktion ausfuehrt", answerB = "ABA beschreibt einen Deadlock zwischen drei Threads die auf verschiedene Ressourcen warten", answerC = "ABA ist ein Speicherleck-Problem das bei verketteten Listen in lock-freiem Code auftritt", answerD = "ABA-Problem tritt nur in garbage-collected Sprachen auf und ist in C++ nicht relevant", correctAnswer = 0, explanation = "Thread 1 liest A, wird suspendiert. Thread 2 aendert A nach B nach A. Thread 1s CAS(A, newValue) gelingt weil der Wert wieder A ist obwohl der Knoten komplett ausgetauscht wurde. Loesung: Tagged Pointer (Version-Counter) oder Hazard Pointers.", difficulty = 4, funFact = "Java AtomicStampedReference loest ABA durch einen mitgefuehrten Integer-Stamp. Das ABA-Problem ist ein Hauptgrund warum lock-freie Speicherverwaltung in C++ so komplex ist."),
    Question(categoryId = 7, questionText = "Was ist Amdahls Gesetz und was sagt es ueber die praktische Grenze der Parallelisierung aus?", answerA = "Amdahls Gesetz besagt dass ein Programm mit p Prozessoren immer p-fach beschleunigt wird", answerB = "Amdahls Gesetz: Der maximale Speedup wird durch den seriellen Anteil s begrenzt. S = 1 / (s + (1-s)/p) naehert sich bei grossem p dem Wert 1/s unabhaengig von der Prozessoranzahl", answerC = "Amdahls Gesetz gilt nur fuer CPU-gebundene Aufgaben nicht fuer I/O-gebundene", answerD = "Amdahls Gesetz wurde durch Gustafsons Gesetz vollstaendig widerlegt und ist ueberholt", correctAnswer = 1, explanation = "Beispiel: 5% serieller Code begrenzt maximalen Speedup auf 20x. Mit 100 CPUs und 5% seriellem Code: S = 1/(0.05 + 0.95/100) = 16.8x statt 100x. Dies erklaert warum massive Parallelisierung selten linearen Speedup erzeugt.", difficulty = 4, funFact = "Gustafsons Law (1988): Bei groesseren Problemen skaliert der parallele Anteil (Weak Scaling vs Strong Scaling). Supercomputer-Benchmarks zeigen oft fast-linearen Speedup weil das Problem mit der Ressource skaliert."),
    Question(categoryId = 7, questionText = "Was ist das Actor-Model und wie unterscheidet es sich von Thread-basierter Nebenlaeuefigkeit?", answerA = "Actors sind leichtgewichtige Threads die Mutex-Locks verwenden um Zustand zu sichern", answerB = "Im Actor-Model kommunizieren Actors ausschliesslich ueber asynchrones Message-Passing, teilen keinen Zustand und verarbeiten Nachrichten sequentiell. Concurrency entsteht durch viele Actors parallel", answerC = "Actor-Model ist eine Java-spezifische Technik und in anderen Sprachen nicht verfuegbar", answerD = "Actors sind identisch mit OS-Prozessen und haben dasselbe Scheduling-Modell", correctAnswer = 1, explanation = "Actors haben: privaten Zustand, Mailbox fuer Nachrichten, Verhalten das Nachrichten sequentiell verarbeitet. Kein shared mutable state bedeutet keine Race Conditions und keine Locks. Erlang, Akka und Pony implementieren das Actor-Model.", difficulty = 4, funFact = "Erlangs Actor-Model ermoeglicht WhatsApps 2 Millionen gleichzeitige Verbindungen auf einem Server. Erlang-Prozesse starten in Mikrosekunden und haben Microsecond-GC-Pausen wegen per-Prozess-Heaps."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen Tail-Call-Optimierung (TCO) und Trampolining?", answerA = "Trampolining ist immer effizienter als TCO weil es weniger Stack-Speicher benoetigt", answerB = "TCO ist eine Compiler-Optimierung die einen Tail-Call in einen Jump umwandelt (kein Stack-Wachstum). Trampolining ist eine Laufzeit-Technik: Funktionen geben Thunks zurueck, eine externe Schleife fuehrt Thunks aus", answerC = "TCO und Trampolining sind identische Techniken mit unterschiedlichen Namen", answerD = "TCO gilt nur fuer direkte Rekursion, Trampolining nur fuer gegenseitige Rekursion", correctAnswer = 1, explanation = "TCO wandelt den Tail-Call in einen goto um und vermeidet Stack-Wachstum. Java JVM unterstuetzt kein TCO. Trampolining ermoeglicht Stack-sichere Rekursion in Sprachen ohne TCO durch eine aeussere Schleife.", difficulty = 4, funFact = "Scheme-Standard (R7RS) verlangt TCO als Pflicht. Kotlin unterstuetzt tailrec fuer direkte Rekursion. Clojure empfiehlt recur da die JVM kein TCO hat."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen Shared-Nothing und Shared-Everything Architektur in verteilten Datenbanken?", answerA = "Shared-Everything-Architektur hat bessere Isolation zwischen Knoten als Shared-Nothing", answerB = "Shared-Nothing: Jeder Knoten hat eigene CPU, RAM und Storage und ist horizontal skalierbar. Shared-Everything: Alle Knoten teilen Storage was Koordination erfordert aber einfacheres Failover ermoeglicht", answerC = "Shared-Nothing ist nur fuer OLAP-Workloads geeignet, Shared-Everything fuer OLTP", answerD = "Shared-Nothing benoetigt keine Netzwerkkommunikation zwischen Knoten fuer Transaktionen", correctAnswer = 1, explanation = "Shared-Nothing (MPP): Jeder Shard hat eigene Daten, Koordinator routet Anfragen. Linear skalierbar aber Cross-Shard-Transaktionen sind teuer. Shared-Disk: Knoten teilen Storage via SAN mit einfacherem Failover aber Koordinationsbedarf.", difficulty = 4, funFact = "Amazon Redshift, Google BigQuery und Snowflake sind Shared-Nothing MPP-Datenbanken. Amazon Aurora kombiniert Shared Storage mit Shared-Nothing-Rechenknoten als innovativen Hybrid-Ansatz."),
    Question(categoryId = 7, questionText = "Was ist Dependent Typing und welche Korrektheitsgarantien ermoeglicht es?", answerA = "Dependent Types sind Typen die von Laufzeitwerten abhaengen (z.B. Vector(n) fuer eine Liste der Laenge n) und ermoeglicht dem Compiler Indexfehler und Laengenpruefungen statisch zu verifizieren", answerB = "Dependent Typing ist ein anderer Begriff fuer generische Programmierung mit Typparametern", answerC = "Dependent Types koennen nur in rein funktionalen Sprachen ohne Seiteneffekte eingesetzt werden", answerD = "Dependent Typing ist ausschliesslich ein theoretisches Konzept ohne praktische Implementierung", correctAnswer = 0, explanation = "Idris, Agda, Coq und Lean 4 unterstuetzen Dependent Types. Beispiel: append :: Vec n a -> Vec m a -> Vec (n+m) a - der Compiler prueft die Laengenaddition statisch. Curry-Howard-Isomorphismus: Propositions-as-Types.", difficulty = 4, funFact = "Coq wurde verwendet um den Vier-Farben-Satz 2004 formal zu verifizieren. CompCert ist ein in Coq verifizierter C-Compiler dessen Korrektheit mathematisch bewiesen ist."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen Deadlock, Livelock und Starvation?", answerA = "Deadlock, Livelock und Starvation sind verschiedene Namen fuer dasselbe Problem", answerB = "Deadlock: Threads blockieren sich gegenseitig zyklisch. Livelock: Threads sind aktiv aber machen keinen nuetzlichen Fortschritt. Starvation: Ein Thread wird dauerhaft von anderen vorgezogen und bekommt nie Ressourcen", answerC = "Livelock ist schwerwiegender als Deadlock weil er mehr CPU-Ressourcen verbraucht", answerD = "Starvation kann nur in Realzeit-Betriebssystemen auftreten", correctAnswer = 1, explanation = "Deadlock: zyklische Wartebedingung, alle blockiert. Livelock: kein Fortschritt aber kein Blockieren - Threads tanzen umeinander. Starvation: unfaire Scheduling-Politik bevorteilt bestimmte Threads dauerhaft. Aging-Algorithmen loesen Starvation.", difficulty = 4, funFact = "Das Livelock-Konzept wird oft durch zwei Personen erklaert die sich in einem schmalen Gang begegnen und gleichzeitig ausweichen. In verteilten Systemen tritt Livelock bei aggressiven Retry-Schleifen ohne Backoff auf."),
    Question(categoryId = 7, questionText = "Was ist Raft-Log-Compaction und wie loest es Raft mittels Snapshots?", answerA = "Raft loest Log-Compaction durch Loeschen alter Log-Eintraege ohne Ersatz was neue Follower-Synchronisation unermoeglicht", answerB = "Da das Raft-Log unbegrenzt waechst machen Follower Snapshots des kompletten Anwendungszustands. Alte Log-Eintraege vor dem Snapshot koennen verworfen werden. Neue Follower erhalten den Snapshot per InstallSnapshot-RPC", answerC = "Raft loest Log-Compaction durch Zusammenfassen mehrerer Log-Eintraege in einen Meta-Eintrag", answerD = "Log-Compaction ist in Raft nicht vorgesehen und muss vom Benutzer manuell implementiert werden", correctAnswer = 1, explanation = "Snapshot enthaelt: letzten Log-Index, letzten Log-Term und den vollstaendigen Anwendungszustand. Nach Snapshot koennen Log-Eintraege bis zum Snapshot-Index verworfen werden. Langsame Follower erhalten den Snapshot via InstallSnapshot.", difficulty = 4, funFact = "etcd (Kubernetes-Backend) implementiert Raft mit Snapshots. Typisches Snapshot-Interval: alle 10.000 Commits. Zu seltene Snapshots fuehren zu langen Raft-Logs und langen Recovery-Zeiten."),
    Question(categoryId = 7, questionText = "Was ist eine Skip-List und welche Zeitkomplexitaet hat sie durchschnittlich fuer Suche, Einfuegen und Loeschen?", answerA = "Eine Skip-List ist ein Array das binaere Suche unterstuetzt mit O(1) fuer alle Operationen", answerB = "Eine Skip-List ist eine probabilistische Datenstruktur aus mehrschichtigen verketteten Listen die Suche, Einfuegen und Loeschen in O(log n) Durchschnittszeit erlaubt durch Vorwaerts-Zeiger auf hoehere Ebenen", answerC = "Skip-Lists haben O(n) Zeitkomplexitaet fuer Suche und sind nur fuer sortierte Iteration optimiert", answerD = "Skip-Lists sind eine Variante von B-Trees und haben identische Komplexitaet und Anwendungsfaelle", correctAnswer = 1, explanation = "Jeder Knoten steigt mit Wahrscheinlichkeit p in die naechste Ebene auf. Bei n Elementen entstehen O(log n) Ebenen. Suche startet in der hoechsten Ebene und faellt herunter wenn das naechste Element zu gross ist. Expected O(log n).", difficulty = 4, funFact = "Redis implementiert Sorted Sets intern als Skip-Lists kombiniert mit Hash-Tables. LevelDB und RocksDB nutzen Skip-Lists fuer den MemTable. William Pugh beschrieb Skip-Lists 1989."),
    Question(categoryId = 7, questionText = "Was ist ein Inverted Index und wie beschleunigt er die Volltextsuche gegenueber einem sequentiellen Scan?", answerA = "Ein Inverted Index kehrt die Reihenfolge der Dokumente um fuer Rueckwaerts-Suche", answerB = "Ein Inverted Index mappt jedes Wort auf eine Liste von Dokumenten die es enthalten (Posting List). Suche nach einem Term ist O(1) fuer den Lookup statt O(n*m) fuer n Dokumente mit m Woertern", answerC = "Inverted Indizes erfordern mehr Speicher als der Volltext und sind nur fuer kleine Korpora geeignet", answerD = "Ein Inverted Index ist identisch mit einem Hash-Index und hat dieselbe Implementierung", correctAnswer = 1, explanation = "Inverted Index: Term -> [docId1, docId2, ...] mit optionalen Term-Frequenzen und Positionen. Schnittmenge von Posting-Listen fuer AND-Suche. Lucene (und damit Elasticsearch, Solr) basiert komplett auf Inverted Indices.", difficulty = 4, funFact = "Googles erste Implementierung nutzte Inverted Indices auf Festplatten in Stanford (1998). Elasticsearch-Shards verwenden Segment-basierte Inverted Indices die bei Merges zusammengefuehrt werden - aehnlich wie LSM-Tree SSTables.")
)
